    57â†’func (ls Labels) stringImpl(addSpace bool) string {
    58â†’	var bytea [1024]byte // On stack to avoid memory allocation while building the output.
    59â†’	b := bytes.NewBuffer(bytea[:0])
    60â†’
    61â†’	b.WriteByte('{')
    62â†’	i := 0
    63â†’	ls.Range(func(l Label) {
    64â†’		if i > 0 {
    65â†’			b.WriteByte(',')
    66â†’			if addSpace {
    67â†’				b.WriteByte(' ')
    68â†’			}
    69â†’		}
    70â†’		if !model.LegacyValidation.IsValidLabelName(l.Name) {
    71â†’			b.Write(strconv.AppendQuote(b.AvailableBuffer(), l.Name))
    72â†’		} else {
    73â†’			b.WriteString(l.Name)
    74â†’		}
    75â†’		b.WriteByte('=')
    76â†’		b.Write(strconv.AppendQuote(b.AvailableBuffer(), l.Value))
    77â†’		i++
    78â†’	})
    79â†’	b.WriteByte('}')
    80â†’	return b.String()
    81â†’}
