   117â†’// IsValid checks if the metric name or label names are valid.
   118â†’func (ls Labels) IsValid(validationScheme model.ValidationScheme) bool {
   119â†’	err := ls.Validate(func(l Label) error {
   120â†’		if l.Name == model.MetricNameLabel {
   121â†’			// If the default validation scheme has been overridden with legacy mode,
   122â†’			// we need to call the special legacy validation checker.
   123â†’			if !validationScheme.IsValidMetricName(l.Value) {
   124â†’				return strconv.ErrSyntax
   125â†’			}
   126â†’		}
