   144â†’// FromMap returns new sorted Labels from the given map.
   145â†’func FromMap(m map[string]string) Labels {
   146â†’	l := make([]Label, 0, len(m))
   147â†’	for k, v := range m {
   148â†’		l = append(l, Label{Name: k, Value: v})
   149â†’	}
   150â†’	return New(l...)
