   163â†’// Del deletes the label of the given name.
   164â†’func (b *Builder) Del(ns ...string) *Builder {
   165â†’	for _, n := range ns {
   166â†’		for i, a := range b.add {
   167â†’			if a.Name == n {
   168â†’				b.add = append(b.add[:i], b.add[i+1:]...)
   169â†’			}
   170â†’		}
   171â†’		b.del = append(b.del, n)
   172â†’	}
   173â†’	return b
   174â†’}
