   177â†’func (b *Builder) Keep(ns ...string) *Builder {
   178â†’	b.base.Range(func(l Label) {
   179â†’		if slices.Contains(ns, l.Name) {
   180â†’			return
   181â†’		}
   182â†’		b.del = append(b.del, l.Name)
   183â†’	})
   184â†’	return b
