   187â†’// Set the name/value pair as a label. A value of "" means delete that label.
   188â†’func (b *Builder) Set(n, v string) *Builder {
   189â†’	if v == "" {
   190â†’		// Empty labels are the same as missing labels.
   191â†’		return b.Del(n)
   192â†’	}
   193â†’	for i, a := range b.add {
   194â†’		if a.Name == n {
   195â†’			b.add[i].Value = v
   196â†’			return b
   197â†’		}
   198â†’	}
   199â†’	b.add = append(b.add, Label{Name: n, Value: v})
   200â†’
   201â†’	return b
   202â†’}
