   204â†’func (b *Builder) Get(n string) string {
   205â†’	// Del() removes entries from .add but Set() does not remove from .del, so check .add first.
   206â†’	for _, a := range b.add {
   207â†’		if a.Name == n {
   208â†’			return a.Value
   209â†’		}
   210â†’	}
   211â†’	if slices.Contains(b.del, n) {
